<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Kanban Board</title>
    <style>
        :root {
            --bg-color: #f0f2f5;
            --column-bg: #ebedf0;
            --card-bg: #ffffff;
            --text-main: #172b4d;
            --text-subtle: #5e6c84;
            --accent: #0052cc;
            --danger: #ef4444;
            --shadow: 0 1px 3px rgba(0,0,0,0.12), 0 1px 2px rgba(0,0,0,0.24);
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            background-color: var(--bg-color);
            color: var(--text-main);
            margin: 0;
            display: flex;
            flex-direction: column;
            align-items: center;
            min-height: 100vh;
        }

        /* Header & Controls */
        header {
            width: 100%;
            padding: 2rem 0;
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 1rem;
        }

        .controls {
            display: flex;
            gap: 0.5rem;
            background: white;
            padding: 1rem;
            border-radius: 8px;
            box-shadow: var(--shadow);
        }

        #new-card {
            padding: 0.6rem 1rem;
            border: 2px solid #dfe1e6;
            border-radius: 4px;
            font-size: 1rem;
            outline: none;
            width: 250px;
        }

        #new-card:focus {
            border-color: var(--accent);
        }

        #add-card {
            padding: 0.6rem 1.2rem;
            background-color: var(--accent);
            color: white;
            border: none;
            border-radius: 4px;
            font-weight: 600;
            cursor: pointer;
            transition: background 0.2s;
        }

        #add-card:hover {
            background-color: #0747a6;
        }

        /* Board Layout */
        .board {
            display: flex;
            gap: 1.5rem;
            padding: 0 1rem 2rem 1rem;
            align-items: flex-start;
            width: 100%;
            max-width: 1200px;
            justify-content: center;
        }

        .column {
            background-color: var(--column-bg);
            border-radius: 8px;
            width: 350px;
            min-height: 400px;
            display: flex;
            flex-direction: column;
            padding: 1rem;
            transition: background-color 0.2s ease;
        }

        .column.drag-over {
            background-color: #dfe1e6;
            outline: 2px dashed var(--accent);
        }

        .column-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 1rem;
            padding: 0 0.5rem;
        }

        .column-header h2 {
            font-size: 1rem;
            text-transform: uppercase;
            letter-spacing: 0.05em;
            margin: 0;
            color: var(--text-subtle);
        }

        .count {
            background: #dfe1e6;
            padding: 2px 8px;
            border-radius: 12px;
            font-size: 0.8rem;
            font-weight: bold;
        }

        /* Card Styling */
        .card-container {
            flex-grow: 1;
            min-height: 50px;
        }

        .card {
            background-color: var(--card-bg);
            border-radius: 6px;
            padding: 1rem;
            margin-bottom: 0.75rem;
            box-shadow: var(--shadow);
            cursor: grab;
            display: flex;
            justify-content: space-between;
            align-items: center;
            word-break: break-word;
            transition: transform 0.1s ease;
        }

        .card:active {
            cursor: grabbing;
        }

        .card-text {
            flex-grow: 1;
            margin-right: 0.5rem;
            font-size: 0.95rem;
        }

        .card-del {
            background: transparent;
            border: none;
            color: var(--text-subtle);
            font-size: 1.2rem;
            cursor: pointer;
            padding: 0 4px;
            line-height: 1;
            transition: color 0.2s;
        }

        .card-del:hover {
            color: var(--danger);
        }

        /* Responsive */
        @media (max-width: 1100px) {
            .board {
                flex-direction: column;
                align-items: center;
            }
            .column {
                width: 90%;
                min-height: auto;
            }
        }
    </style>
</head>
<body>

<header>
    <h1>Kanban Board</h1>
    <div class="controls">
        <input type="text" id="new-card" placeholder="Enter task title..." autocomplete="off">
        <button id="add-card">Add Card</button>
    </div>
</header>

<main class="board">
    <!-- To Do Column -->
    <section class="column" id="col-todo">
        <div class="column-header">
            <h2>To Do</h2>
            <span class="count">0</span>
        </div>
        <div class="card-container"></div>
    </section>

    <!-- Doing Column -->
    <section class="column" id="col-doing">
        <div class="column-header">
            <h2>Doing</h2>
            <span class="count">0</span>
        </div>
        <div class="card-container"></div>
    </section>

    <!-- Done Column -->
    <section class="column" id="col-done">
        <div class="column-header">
            <h2>Done</h2>
            <span class="count">0</span>
        </div>
        <div class="card-container"></div>
    </section>
</main>

<script>
    const input = document.getElementById('new-card');
    const addBtn = document.getElementById('add-card');
    const columns = document.querySelectorAll('.column');
    const containers = document.querySelectorAll('.card-container');

    // --- Core Logic ---

    function init() {
        loadState();
        setupEventListeners();
        updateCounts();
    }

    function setupEventListeners() {
        addBtn.addEventListener('click', addCard);
        input.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') addCard();
        });

        // Drag and Drop Listeners
        containers.forEach(container => {
            container.addEventListener('dragover', handleDragOver);
            container.addEventListener('drop', handleDrop);
            container.addEventListener('dragleave', handleDragLeave);
        });

        columns.forEach(col => {
            col.addEventListener('dragover', handleDragOver);
            col.addEventListener('dragleave', handleDragLeave);
        });
    }

    function addCard() {
        const text = input.value.trim();
        if (!text) return;

        const cardId = 'card-' + Date.now();
        createCardElement(cardId, text, 'col-todo');

        input.value = '';
        saveState();
        updateCounts();
    }

    function createCardElement(id, text, colId) {
        const card = document.createElement('div');
        card.className = 'card';
        card.id = id;
        card.draggable = true;
        card.addEventListener('dragstart', handleDragStart);

        const textSpan = document.createElement('span');
        textSpan.className = 'card-text';
        textSpan.textContent = text;

        const delBtn = document.createElement('button');
        delBtn.className = 'card-del';
        delBtn.innerHTML = '&times;';
        delBtn.onclick = () => {
            card.remove();
            saveState();
            updateCounts();
        };

        card.appendChild(textSpan);
        card.appendChild(delBtn);

        const targetCol = document.getElementById(colId);
        targetCol.querySelector('.card-container').appendChild(card);
    }

    // --- Drag and Drop Handlers ---

    let draggedCardId = null;

    function handleDragStart(e) {
        draggedCardId = e.target.id;
        e.dataTransfer.setData('text/plain', e.target.id);
        // Small delay to allow the ghost image to be created before opacity changes
        setTimeout(() => e.target.style.opacity = '0.5', 0);
    }

    function handleDragOver(e) {
        e.preventDefault(); // Necessary to allow drop
        const target = e.target.closest('.column');
        if (target) {
            target.classList.add('drag-over');
        }
    }

    function handleDragLeave(e) {
        const target = e.target.closest('.column');
        if (target) {
            target.classList.remove('drag-over');
        }
    }

    function handleDrop(e) {
        e.preventDefault();
        const column = e.target.closest('.column');
        if (!column) return;

        column.classList.remove('drag-over');
        const cardId = e.dataTransfer.getData('text/plain');
        const card = document.getElementById(cardId);

        if (card) {
            // Restore opacity
            card.style.opacity = '1';

            // Move to the container of the dropped column
            const container = column.querySelector('.card-container');
            container.appendChild(card);

            saveState();
            updateCounts();
        }
    }

    // --- State Management ---

    function updateCounts() {
        document.querySelectorAll('.column').forEach(col => {
            const count = col.querySelectorAll('.card').length;
            col.querySelector('.count').textContent = count;
        });
    }

    function saveState() {
        const state = [];
        document.querySelectorAll('.column').forEach(col => {
            const colId = col.id;
            col.querySelectorAll('.card').forEach(card => {
                state.push({
                    id: card.id,
                    text: card.querySelector('.card-text').textContent,
                    colId: colId
                });
            });
        });
        localStorage.setItem('kanban_board_data', JSON.stringify(state));
    }

    function loadState() {
        const saved = localStorage.getItem('kanban_board_data');
        if (!saved) return;

        try {
            const state = JSON.parse(saved);
            state.forEach(item => {
                createCardElement(item.id, item.text, item.colId);
            });
        } catch (e) {
            console.error("Failed to load board state", e);
        }
    }

    // Initialize the app
    init();

</script>

</body>
</html>
